"use strict";(globalThis.webpackChunkhumbl_doc=globalThis.webpackChunkhumbl_doc||[]).push([[8057],{5321(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"architectureSidebar":[{"type":"category","label":"Architecture Overview","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/humbl-doc/architecture/module-map","label":"Module Map","docId":"architecture/module-map","unlisted":false},{"type":"category","label":"Core Subsystems","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/architecture/subsystems/langchain-framework","label":"LangChain Framework (Dart Ports)","docId":"architecture/subsystems/langchain-framework","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/pipeline","label":"Pipeline","docId":"architecture/subsystems/pipeline","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/tool-system","label":"Tool System","docId":"architecture/subsystems/tool-system","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/security","label":"Security & Access Control","docId":"architecture/subsystems/security","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/platform-abstraction","label":"Platform Abstraction","docId":"architecture/subsystems/platform-abstraction","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/memory","label":"Memory System","docId":"architecture/subsystems/memory","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/lm-gateway","label":"LM Gateway","docId":"architecture/subsystems/lm-gateway","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/devices-sdk","label":"Devices SDK","docId":"architecture/subsystems/devices-sdk","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/subsystems/voice-io","label":"Voice I/O","docId":"architecture/subsystems/voice-io","unlisted":false}]},{"type":"category","label":"Supporting Systems","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/architecture/supporting/resilience","label":"Resilience","docId":"architecture/supporting/resilience","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/input-system","label":"Input System","docId":"architecture/supporting/input-system","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/settings","label":"Settings","docId":"architecture/supporting/settings","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/payments-quota","label":"Payments & Quota","docId":"architecture/supporting/payments-quota","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/logging","label":"Logging","docId":"architecture/supporting/logging","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/mcp","label":"MCP Integration","docId":"architecture/supporting/mcp","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/services-agent","label":"Services & Agent","docId":"architecture/supporting/services-agent","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/supporting/cloud-agents","label":"Cloud Agent Backend","docId":"architecture/supporting/cloud-agents","unlisted":false}]},{"type":"link","href":"/humbl-doc/architecture/data-flow","label":"Data Flow","docId":"architecture/data-flow","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/db-layout","label":"Database Layout","docId":"architecture/db-layout","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/startup-sequence","label":"Startup Sequence","docId":"architecture/startup-sequence","unlisted":false},{"type":"link","href":"/humbl-doc/architecture/concurrency-model","label":"Concurrency Model","docId":"architecture/concurrency-model","unlisted":false}],"href":"/humbl-doc/architecture/overview"}],"statusSidebar":[{"type":"category","label":"Implementation Status","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/humbl-doc/status/gap-analysis","label":"Gap Analysis","docId":"status/gap-analysis","unlisted":false},{"type":"link","href":"/humbl-doc/status/test-coverage","label":"Test Coverage","docId":"status/test-coverage","unlisted":false},{"type":"link","href":"/humbl-doc/status/module-completion","label":"Module Completion","docId":"status/module-completion","unlisted":false},{"type":"link","href":"/humbl-doc/status/roadmap","label":"Roadmap","docId":"status/roadmap","unlisted":false}],"href":"/humbl-doc/status/overview"}],"apiSidebar":[{"type":"category","label":"API Reference","collapsible":true,"collapsed":false,"items":[{"type":"category","label":"Pipeline","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/pipeline/pipeline-orchestrator","label":"PipelineOrchestrator","docId":"api/pipeline/pipeline-orchestrator","unlisted":false},{"type":"link","href":"/humbl-doc/api/pipeline/pipeline-state","label":"PipelineState","docId":"api/pipeline/pipeline-state","unlisted":false},{"type":"link","href":"/humbl-doc/api/pipeline/state-graph","label":"StateGraph","docId":"api/pipeline/state-graph","unlisted":false},{"type":"link","href":"/humbl-doc/api/pipeline/nodes","label":"Pipeline Nodes","docId":"api/pipeline/nodes","unlisted":false}]},{"type":"category","label":"Tool System","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/tools/humbl-tool","label":"HumblTool","docId":"api/tools/humbl-tool","unlisted":false},{"type":"link","href":"/humbl-doc/api/tools/tool-registry","label":"ToolRegistry","docId":"api/tools/tool-registry","unlisted":false},{"type":"link","href":"/humbl-doc/api/tools/models","label":"Tool Models","docId":"api/tools/models","unlisted":false}]},{"type":"category","label":"LM Gateway","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/lm-gateway/i-lm-gateway","label":"ILmGateway","docId":"api/lm-gateway/i-lm-gateway","unlisted":false},{"type":"link","href":"/humbl-doc/api/lm-gateway/connectors","label":"Connectors","docId":"api/lm-gateway/connectors","unlisted":false},{"type":"link","href":"/humbl-doc/api/lm-gateway/scheduling","label":"Scheduling","docId":"api/lm-gateway/scheduling","unlisted":false}]},{"type":"category","label":"Memory","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/memory/i-memory-service","label":"IMemoryService","docId":"api/memory/i-memory-service","unlisted":false},{"type":"link","href":"/humbl-doc/api/memory/conversation-store","label":"ConversationStore","docId":"api/memory/conversation-store","unlisted":false},{"type":"link","href":"/humbl-doc/api/memory/vector-store","label":"Vector Store","docId":"api/memory/vector-store","unlisted":false},{"type":"link","href":"/humbl-doc/api/memory/embedding-gateway","label":"EmbeddingGateway","docId":"api/memory/embedding-gateway","unlisted":false}]},{"type":"category","label":"Devices SDK","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/devices/i-peripheral-provider","label":"IPeripheralProvider","docId":"api/devices/i-peripheral-provider","unlisted":false},{"type":"link","href":"/humbl-doc/api/devices/i-connected-device","label":"IConnectedDevice","docId":"api/devices/i-connected-device","unlisted":false},{"type":"link","href":"/humbl-doc/api/devices/device-registry","label":"DeviceRegistry","docId":"api/devices/device-registry","unlisted":false}]},{"type":"category","label":"Security","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/security/access-control","label":"AccessControl","docId":"api/security/access-control","unlisted":false},{"type":"link","href":"/humbl-doc/api/security/permission-service","label":"PermissionService","docId":"api/security/permission-service","unlisted":false},{"type":"link","href":"/humbl-doc/api/security/confirmation-service","label":"ConfirmationService","docId":"api/security/confirmation-service","unlisted":false}]},{"type":"category","label":"Resources","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/resources/hardware-resource-manager","label":"IHardwareResourceManager","docId":"api/resources/hardware-resource-manager","unlisted":false},{"type":"link","href":"/humbl-doc/api/resources/resource-lease","label":"ResourceLease","docId":"api/resources/resource-lease","unlisted":false}]},{"type":"category","label":"Services & Agent","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/services/humbl-agent","label":"HumblAgent","docId":"api/services/humbl-agent","unlisted":false},{"type":"link","href":"/humbl-doc/api/services/service-event-bus","label":"ServiceEventBus","docId":"api/services/service-event-bus","unlisted":false}]},{"type":"category","label":"Voice I/O","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/voice/vad-stt-tts","label":"VAD, STT, TTS","docId":"api/voice/vad-stt-tts","unlisted":false},{"type":"link","href":"/humbl-doc/api/voice/voice-session-runner","label":"VoiceSessionRunner","docId":"api/voice/voice-session-runner","unlisted":false}]},{"type":"category","label":"Platform","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/api/platform/platform-factory","label":"PlatformFactory","docId":"api/platform/platform-factory","unlisted":false},{"type":"link","href":"/humbl-doc/api/platform/manager-interfaces","label":"Manager Interfaces","docId":"api/platform/manager-interfaces","unlisted":false}]}],"href":"/humbl-doc/api/"}],"guideSidebar":[{"type":"category","label":"Developer Guide","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/humbl-doc/guide/project-setup","label":"Project Setup","docId":"guide/project-setup","unlisted":false},{"type":"category","label":"How-To Guides","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/humbl-doc/guide/howto/add-a-tool","label":"Add a Tool","docId":"guide/howto/add-a-tool","unlisted":false},{"type":"link","href":"/humbl-doc/guide/howto/add-a-platform-manager","label":"Add a Platform Manager","docId":"guide/howto/add-a-platform-manager","unlisted":false},{"type":"link","href":"/humbl-doc/guide/howto/add-an-lm-connector","label":"Add an LM Connector","docId":"guide/howto/add-an-lm-connector","unlisted":false},{"type":"link","href":"/humbl-doc/guide/howto/add-a-device-provider","label":"Add a Device Provider","docId":"guide/howto/add-a-device-provider","unlisted":false}]},{"type":"category","label":"Patterns & Conventions","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/humbl-doc/guide/patterns/immutable-state","label":"Immutable State","docId":"guide/patterns/immutable-state","unlisted":false},{"type":"link","href":"/humbl-doc/guide/patterns/gate-model","label":"Gate Model","docId":"guide/patterns/gate-model","unlisted":false},{"type":"link","href":"/humbl-doc/guide/patterns/naming-conventions","label":"Naming Conventions","docId":"guide/patterns/naming-conventions","unlisted":false},{"type":"link","href":"/humbl-doc/guide/patterns/testing","label":"Testing","docId":"guide/patterns/testing","unlisted":false}]}],"href":"/humbl-doc/guide/getting-started"}]},"docs":{"api/devices/device-registry":{"id":"api/devices/device-registry","title":"DeviceRegistry","description":"Singleton registry for peripheral device discovery, provider management, and connection lifecycle.","sidebar":"apiSidebar"},"api/devices/i-connected-device":{"id":"api/devices/i-connected-device","title":"IConnectedDevice","description":"Represents a connected peripheral device with capability interfaces.","sidebar":"apiSidebar"},"api/devices/i-peripheral-provider":{"id":"api/devices/i-peripheral-provider","title":"IPeripheralProvider","description":"Interface for adding new peripheral devices to the Humbl ecosystem. Works for any form factor: glasses, hearing aids, voice pucks, earbuds, etc.","sidebar":"apiSidebar"},"api/index":{"id":"api/index","title":"API Reference","description":"Complete API reference for the Humbl project. The project consists of four framework packages (packages/) and the main humbl_core Flutter plugin.","sidebar":"apiSidebar"},"api/lm-gateway/connectors":{"id":"api/lm-gateway/connectors","title":"Connectors","description":"Each LM provider (Anthropic, OpenAI, Ollama, etc.) has a connector that knows how to validate configs, test connectivity, and create provider instances.","sidebar":"apiSidebar"},"api/lm-gateway/i-lm-gateway":{"id":"api/lm-gateway/i-lm-gateway","title":"ILmGateway","description":"Top-level gateway interface. Pure routing engine that abstracts all LM providers behind a single API. The concrete HumblLmGateway implementation wraps the litellm_dart Router for provider selection and supports 5 routing strategies (simple, costBased, leastBusy, latencyBased, usageBased).","sidebar":"apiSidebar"},"api/lm-gateway/scheduling":{"id":"api/lm-gateway/scheduling","title":"Scheduling","description":"The LM scheduling layer manages request priority and queuing. Real-time user requests preempt background tasks, and background requests are queued when the model is busy.","sidebar":"apiSidebar"},"api/memory/conversation-store":{"id":"api/memory/conversation-store","title":"ConversationStore","description":"Persistent conversation turn store backed by SQLite, implementing BaseChatMessageHistory from langchain_dart. Stores every user/assistant/tool turn with quality scoring. Uses LangChain message types (HumanMessage, AIMessage, ToolMessage) for interoperability with LangChain chains and agents.","sidebar":"apiSidebar"},"api/memory/embedding-gateway":{"id":"api/memory/embedding-gateway","title":"EmbeddingGateway","description":"Routes embedding requests to the best available provider with automatic fallback.","sidebar":"apiSidebar"},"api/memory/i-memory-service":{"id":"api/memory/i-memory-service","title":"IMemoryService","description":"Unified memory abstraction for 3 tiers, extending BaseMemory from langchain_dart. T1 (performance cache) was removed due to near-zero cache hit rate for NLP workloads. All storage is SQLite-backed.","sidebar":"apiSidebar"},"api/memory/vector-store":{"id":"api/memory/vector-store","title":"Vector Store","description":"IVectorStore and SqliteVecStore for on-device semantic search using 384-dimensional embeddings.","sidebar":"apiSidebar"},"api/pipeline/nodes":{"id":"api/pipeline/nodes","title":"Pipeline Nodes","description":"All 7 nodes in the pipeline graph. Each node reads specific fields from PipelineState, performs its work, and returns a modified copy.","sidebar":"apiSidebar"},"api/pipeline/pipeline-orchestrator":{"id":"api/pipeline/pipeline-orchestrator","title":"PipelineOrchestrator","description":"Pre-wired pipeline graph that supports concurrent runs. Entry point for processing user utterances.","sidebar":"apiSidebar"},"api/pipeline/pipeline-state":{"id":"api/pipeline/pipeline-state","title":"PipelineState","description":"The immutable typed state object that flows through every node in the graph. Each node reads the fields it needs and returns a modified copy via copyWith().","sidebar":"apiSidebar"},"api/pipeline/state-graph":{"id":"api/pipeline/state-graph","title":"StateGraph","description":"Deterministic routing engine. LangGraph-compatible pattern in pure Dart. No LLM involved in routing -- nodes and edges are static, testable, zero token cost.","sidebar":"apiSidebar"},"api/platform/manager-interfaces":{"id":"api/platform/manager-interfaces","title":"Manager Interfaces","description":"All 25+ I-prefix interfaces that define platform capabilities. Each interface lives in its own subfolder with per-platform implementations.","sidebar":"apiSidebar"},"api/platform/platform-factory":{"id":"api/platform/platform-factory","title":"PlatformFactory","description":"Runtime platform selection. Static factory methods return the correct concrete implementation for the current platform.","sidebar":"apiSidebar"},"api/resources/hardware-resource-manager":{"id":"api/resources/hardware-resource-manager","title":"IHardwareResourceManager","description":"Lease-based hardware resource control. Prevents two tools from fighting over the camera, mic, or other shared hardware.","sidebar":"apiSidebar"},"api/resources/resource-lease":{"id":"api/resources/resource-lease","title":"ResourceLease","description":"Immutable lease on a hardware resource. Renewals produce a new instance rather than mutating in place.","sidebar":"apiSidebar"},"api/security/access-control":{"id":"api/security/access-control","title":"AccessControl","description":"Gate 1 enforcement logic. Checks if a caller\'s access level permits invoking a tool.","sidebar":"apiSidebar"},"api/security/confirmation-service":{"id":"api/security/confirmation-service","title":"ConfirmationService","description":"Orchestrates user confirmation across multiple providers when a tool requires explicit user consent before executing.","sidebar":"apiSidebar"},"api/security/permission-service":{"id":"api/security/permission-service","title":"PermissionService","description":"OS-level permission probing and tool state management.","sidebar":"apiSidebar"},"api/services/humbl-agent":{"id":"api/services/humbl-agent","title":"HumblAgent","description":"The always-free main agent. Event loop dispatcher that maps to LangGraph\'s AgentExecutor. Never blocks, supports concurrent pipeline runs, and manages scout agents.","sidebar":"apiSidebar"},"api/services/service-event-bus":{"id":"api/services/service-event-bus","title":"ServiceEventBus","description":"Typed pub/sub event bus for decoupled inter-service communication. Services publish events; other services subscribe by type.","sidebar":"apiSidebar"},"api/tools/humbl-tool":{"id":"api/tools/humbl-tool","title":"HumblTool","description":"Abstract base class for every tool in the registry, extending BaseTool from langchaindart. Every Humbl tool is a valid LangChain tool -- it can be used in LCEL chains, passed to createreact_agent(), and discovered by any LangChain-compatible system. Schema is MCP-compatible so any LLM can discover and invoke tools.","sidebar":"apiSidebar"},"api/tools/models":{"id":"api/tools/models","title":"Tool Models","description":"Key enums and data classes used throughout the tool system.","sidebar":"apiSidebar"},"api/tools/tool-registry":{"id":"api/tools/tool-registry","title":"ToolRegistry","description":"Pure registration and discovery. No execution methods -- tool execution is handled by HumblTool\'s @nonVirtual templates.","sidebar":"apiSidebar"},"api/voice/vad-stt-tts":{"id":"api/voice/vad-stt-tts","title":"VAD, STT, TTS","description":"Voice pipeline interfaces for Voice Activity Detection, Speech-to-Text, and Text-to-Speech.","sidebar":"apiSidebar"},"api/voice/voice-session-runner":{"id":"api/voice/voice-session-runner","title":"VoiceSessionRunner","description":"Main voice pipeline orchestrator. Discovers the mic tool via ToolRegistry, feeds audio through AEC, RingBuffer, VAD, STT, pipeline dispatch, and TTS with barge-in support.","sidebar":"apiSidebar"},"architecture/concurrency-model":{"id":"architecture/concurrency-model","title":"Concurrency Model","description":"Humbl runs multiple concurrent operations: LM inference, pipeline processing, tool execution, voice streaming, and hardware resource management. This page documents how concurrency is handled at each layer without traditional locking.","sidebar":"architectureSidebar"},"architecture/data-flow":{"id":"architecture/data-flow","title":"Data Flow","description":"This page traces how data moves through the Humbl system for the four primary interaction patterns: text input, voice input, tool execution, and cloud escalation. Each flow includes a sequence diagram followed by a step-by-step narrative explaining what happens, what data transforms, and why that design choice was made.","sidebar":"architectureSidebar"},"architecture/db-layout":{"id":"architecture/db-layout","title":"Database Layout","description":"Humbl uses four SQLite databases, each dedicated to a specific concern. All databases live in the app\'s support directory (getApplicationSupportDirectory()). There is no shared-nothing boundary -- each service owns its tables and indexes within its database file.","sidebar":"architectureSidebar"},"architecture/module-map":{"id":"architecture/module-map","title":"Module Map","description":"Complete inventory of all packages and modules in the Humbl project. The project consists of 4 framework packages (under packages/) and the main humbl_core Flutter plugin.","sidebar":"architectureSidebar"},"architecture/overview":{"id":"architecture/overview","title":"Architecture Overview","description":"Humbl is a voice-native, edge-first AI application that connects to smart accessories \u2014 glasses, pendants, AI pins \u2014 and smartphones as extension devices. The system routes 60-80% of processing on-device through a small language model (SLM), falling back to cloud providers for complex or multi-step tasks. A multi-provider architecture lets users independently configure LM, STT, TTS, and embedding providers to their requirements.","sidebar":"architectureSidebar"},"architecture/startup-sequence":{"id":"architecture/startup-sequence","title":"Startup Sequence","description":"The humbl_app/lib/main.dart file orchestrates a 20-step startup that initializes every service, connects all interfaces, and launches the app widget. This page documents each step, its dependencies, and what it produces.","sidebar":"architectureSidebar"},"architecture/subsystems/devices-sdk":{"id":"architecture/subsystems/devices-sdk","title":"Devices SDK","description":"The Devices SDK provides a provider-based abstraction for smart glasses hardware. Third-party developers implement IPeripheralProvider to add support for new glasses. The SDK normalizes different hardware into a capability model that tools can query, so a \\"take photo\\" tool works identically whether the user wears Even G1, Frame, or Humbl Glasses.","sidebar":"architectureSidebar"},"architecture/subsystems/langchain-framework":{"id":"architecture/subsystems/langchain-framework","title":"LangChain Framework (Dart Ports)","description":"Humbl\'s AI layer is built on native Dart ports of four industry-standard Python frameworks. These are not wrappers \u2014 they are full reimplementations in Dart, following the same abstractions and interfaces as their Python counterparts. All Humbl features are extensions of these ports.","sidebar":"architectureSidebar"},"architecture/subsystems/lm-gateway":{"id":"architecture/subsystems/lm-gateway","title":"LM Gateway","description":"The LM Gateway is Humbl\'s pure routing engine for language model inference, built on top of the litellm_dart Router. It abstracts away which model, provider, and runtime is used -- the caller sends a request and the gateway figures out the best available option based on policy, tier, connectivity, cooldown state, and health.","sidebar":"architectureSidebar"},"architecture/subsystems/memory":{"id":"architecture/subsystems/memory","title":"Memory System","description":"Humbl\'s memory system provides three storage tiers -- all backed by SQLite, with interfaces extending LangChain base classes from langchain_dart. The original T1 performance cache was removed after analysis showed near-zero cache hit rates for NLP workloads. Local storage is cheap (~20MB for 10K memories), so there is no eviction pressure -- importance scoring is used for context assembly priority, not deletion.","sidebar":"architectureSidebar"},"architecture/subsystems/pipeline":{"id":"architecture/subsystems/pipeline","title":"Pipeline","description":"The Humbl pipeline is a LangGraph-compatible deterministic router implemented in pure Dart. No LLM is involved in routing decisions -- nodes and edges are static, testable, and zero token cost. The LM is only invoked inside ClassifyNode for intent classification; all other routing is rule-based.","sidebar":"architectureSidebar"},"architecture/subsystems/platform-abstraction":{"id":"architecture/subsystems/platform-abstraction","title":"Platform Abstraction","description":"Every device capability in Humbl is accessed through an I-prefix interface. Concrete implementations are selected at runtime by PlatformFactory based on Platform.isAndroid, Platform.isIOS, etc. Tools receive managers via constructor injection and never depend on concrete platform implementations.","sidebar":"architectureSidebar"},"architecture/subsystems/security":{"id":"architecture/subsystems/security","title":"Security & Access Control","description":"Humbl uses a five-gate security model that controls who can invoke tools, what state they must be in, what resources they can access, and whether the user has explicitly permitted the action. Every gate is enforced in HumblTool\'s @nonVirtual template methods -- subclasses cannot bypass them.","sidebar":"architectureSidebar"},"architecture/subsystems/tool-system":{"id":"architecture/subsystems/tool-system","title":"Tool System","description":"Humbl\'s tool system provides 70+ tools across 16 domain files, all MCP-compatible. Every tool is self-describing with JSON Schema input/output, so any LLM (local or cloud) can discover and invoke tools via toMcpSchema() without Humbl-specific integration.","sidebar":"architectureSidebar"},"architecture/subsystems/voice-io":{"id":"architecture/subsystems/voice-io","title":"Voice I/O","description":"The voice I/O system orchestrates the full VAD -> STT -> Pipeline -> TTS cycle for hands-free operation. It handles microphone source selection, acoustic echo cancellation, barge-in detection, and zero-audio-loss buffering.","sidebar":"architectureSidebar"},"architecture/supporting/cloud-agents":{"id":"architecture/supporting/cloud-agents","title":"Cloud Agent Backend","description":"Humbl uses a local-primary, cloud-extended agent architecture. The main Humbl Agent always runs in the app on-device. For tasks that require cloud resources (web search, long-running workflows, multi-step reasoning), it dispatches a cloud agent job and communicates via a bidirectional message bus.","sidebar":"architectureSidebar"},"architecture/supporting/input-system":{"id":"architecture/supporting/input-system","title":"Input System","description":"The input system provides a unified pipeline entry point for all input modalities: text, voice, video, gestures, sensors, MCP push events, scheduled triggers, and agent handoffs. All sources are normalized into a single stream that the pipeline consumes.","sidebar":"architectureSidebar"},"architecture/supporting/logging":{"id":"architecture/supporting/logging","title":"Logging","description":"Humbl\'s logging system has three tiers: console logging via HumblLogger, persistent structured logging via PartitionedJournal, and confidential logging via ILogEncryptor. All tiers are connected by TraceId for end-to-end correlation across pipeline runs, tool executions, and cloud requests.","sidebar":"architectureSidebar"},"architecture/supporting/mcp":{"id":"architecture/supporting/mcp","title":"MCP Integration","description":"Humbl acts as a Model Context Protocol (MCP) host, allowing users to install external MCP servers and expose their tools to the LM. MCP tools are wrapped as standard HumblTool instances, always capped at AccessLevel.standard for security.","sidebar":"architectureSidebar"},"architecture/supporting/payments-quota":{"id":"architecture/supporting/payments-quota","title":"Payments & Quota","description":"The payments and quota system tracks cloud LM usage, enforces tier limits, and provides rate limiting. Client-side enforcement is for UX only (immediate feedback to the user before a request is sent). Server-side enforcement via Supabase Edge Functions is authoritative -- the client can be bypassed, but the server cannot.","sidebar":"architectureSidebar"},"architecture/supporting/resilience":{"id":"architecture/supporting/resilience","title":"Resilience","description":"Humbl\'s resilience layer provides automatic recovery from transient failures without burdening tool authors or pipeline nodes with retry logic. Three components work together: CircuitBreaker prevents hammering a failing service, RetryPolicy controls backoff timing, and ResilientExecutor orchestrates both. A fourth component, Heartbeat, detects silent failures through push-first monitoring with poll fallback.","sidebar":"architectureSidebar"},"architecture/supporting/services-agent":{"id":"architecture/supporting/services-agent","title":"Services & Agent","description":"The services layer provides the top-level orchestration for Humbl: the always-free HumblAgent dispatcher, automatic session management, and a typed event bus for inter-service communication.","sidebar":"architectureSidebar"},"architecture/supporting/settings":{"id":"architecture/supporting/settings","title":"Settings","description":"The settings system provides a generic, namespace-based, reactive settings registry. Modules register ISettingsProvider implementations that declare their settings. The central SettingsService handles persistence (SQLite), access control (per-setting), reactive streams, and cloud sync readiness.","sidebar":"architectureSidebar"},"compliance/compliance-standards":{"id":"compliance/compliance-standards","title":"Humbl AI -- Compliance & Standards Tracking","description":"This document tracks Humbl AI\'s compliance posture across security, privacy, AI governance, code quality, accessibility, and data handling. It reflects what is implemented today versus what is required for each tier."},"guide/getting-started":{"id":"guide/getting-started","title":"Getting Started","description":"Prerequisites, clone, build, and test instructions for the Humbl codebase.","sidebar":"guideSidebar"},"guide/howto/add-a-device-provider":{"id":"guide/howto/add-a-device-provider","title":"Add a Device Provider","description":"Implement support for a new smart glasses or peripheral device.","sidebar":"guideSidebar"},"guide/howto/add-a-platform-manager":{"id":"guide/howto/add-a-platform-manager","title":"Add a Platform Manager","description":"Add a new platform capability interface with per-platform implementations.","sidebar":"guideSidebar"},"guide/howto/add-a-tool":{"id":"guide/howto/add-a-tool","title":"Add a Tool","description":"Step-by-step guide to building a new tool for the Humbl tool system.","sidebar":"guideSidebar"},"guide/howto/add-an-lm-connector":{"id":"guide/howto/add-an-lm-connector","title":"Add an LM Connector","description":"Implement a new LM provider connector to support a new cloud API, local server, or on-device runtime.","sidebar":"guideSidebar"},"guide/patterns/gate-model":{"id":"guide/patterns/gate-model","title":"Gate Model","description":"Every tool execution passes through five sequential gates before business logic runs. The gates are enforced by @nonVirtual template methods on HumblTool -- subclasses cannot bypass them.","sidebar":"guideSidebar"},"guide/patterns/immutable-state":{"id":"guide/patterns/immutable-state","title":"Immutable State","description":"All state objects in the pipeline use immutable data with copyWith() for transitions. This eliminates an entire class of concurrency bugs.","sidebar":"guideSidebar"},"guide/patterns/naming-conventions":{"id":"guide/patterns/naming-conventions","title":"Naming Conventions","description":"Consistent naming rules across the codebase.","sidebar":"guideSidebar"},"guide/patterns/testing":{"id":"guide/patterns/testing","title":"Testing","description":"How to write tests for Humbl modules.","sidebar":"guideSidebar"},"guide/project-setup":{"id":"guide/project-setup","title":"Project Setup","description":"SDK versions, dependency management, and per-platform build instructions.","sidebar":"guideSidebar"},"status/gap-analysis":{"id":"status/gap-analysis","title":"Gap Analysis","description":"Full category-by-category breakdown of implementation status. Each row shows items completed, partially implemented, and missing.","sidebar":"statusSidebar"},"status/module-completion":{"id":"status/module-completion","title":"Module Completion","description":"Per-module completion status for all packages. Framework packages (packages/) are listed first, followed by humbl_core modules.","sidebar":"statusSidebar"},"status/overview":{"id":"status/overview","title":"Implementation Status","description":"Summary Dashboard","sidebar":"statusSidebar"},"status/roadmap":{"id":"status/roadmap","title":"Roadmap","description":"Development priorities ordered by impact and dependency chain.","sidebar":"statusSidebar"},"status/test-coverage":{"id":"status/test-coverage","title":"Test Coverage","description":"Summary","sidebar":"statusSidebar"}}}}')}}]);